131→        $rec = RecruitmentProcessionMd::where('resume_id', $input['resume_id'])->orderBy('id', 'desc')->first();
132→        $re = ResumeMd::find($input['resume_id']);
133→        $job_id = empty($rec) ? (empty($re) ? 0 : $re->job_id) : $rec->job_id;
134→        $rec_id = empty($rec) ? 0 : $rec->id;
135→        setAuthorityToken($input['authorized_token'], $input['resume_id'], 'anonymous', 86400 * 3);
136→        $link = $this->service->resumeShareLink($input['authorized_token']);
137→        app(\App\Service\ResumeOperationService::class)->record($input['resume_id'], 'resume_share', $re->status, $job_id ?: 0, '简历分享', '', ['rec_pro_id' => $rec_id]);
