148→    /**
149→     * 转初筛.
150→     *
151→     * @param Request $request
152→     * @return JsonResponse
153→     */
154→    public function toInitScreening(Request $request)
155→    {
156→        $input = Arr::only($request->all(), [
157→            'resumes', 'job_id',
158→        ]);
159→
160→        // 验证合法性
161→        if (count($input['resumes']) != count($input['resumes'], 1)) { // 默认不计算多维数组中的元素，1计算多维数组中的所有元素
162→            return $this->responseJsonFail(__('my_api.resume_param_err'), 843);
163→        }
164→        $rec = RecruitmentProcessionMd::whereIn('resume_id', $input['resumes'])->whereIn('status', RecruitmentProcessionMd::REC_PROCESSING_STATUS)->get()->toArray();
165→        if (!empty($rec)) {
166→            $res = ResumeMd::whereIn('id', array_column($rec, 'resume_id'))->pluck('username')->toArray();
167→
168→            return $this->responseJsonFail(__('my_api.can_not_init_screening', ['res' => implode(',', app(\App\Service\EncryptService::class)->markEncr($res))]), 450);
169→        }
170→        $rec2 = RecruitmentProcessionMd::whereIn('resume_id', $input['resumes'])->where('status', RecruitmentProcessionMd::REC_STATUS['已入职'])->get()->toArray();
171→        if (!empty($rec2)) {
172→            $res = ResumeMd::whereIn('id', array_column($rec2, 'resume_id'))->pluck('username')->toArray();
173→            return $this->responseJsonFail(__('my_api.can_not_init_screening2', ['res' => implode(',', app(\App\Service\EncryptService::class)->markEncr($res))]), 450);
174→        }
175→
176→        $create_data = ResumeMd::whereIn('id', $input['resumes'])->selectRaw('id as resume_id')->get()->toArray();
177→        db()->beginTransaction();
178→        $rec_pro_ids = [];
179→        try {
180→            foreach ($create_data as $resume) {
181→                $rec = RecruitmentProcessionMd::create($resume + ['job_id' => $input['job_id'], 'status' => RecruitmentProcessionMd::REC_STATUS['初筛']]);
182→
183→                // 记录这一操作
184→                $service = app(\App\Service\ResumeOperationService::class);
185→                $service->recordByType(
186→                    $rec->id,
187→                    'recruitment_procession',
188→                    $service->getType(RecruitmentProcessionMd::REC_STATUS['初筛']),
189→                    '',
190→                    '转初筛',
