 71→    {
 72→        /** @var RecruitmentNeedsMd $recruitment */
 73→        $recruitment = RecruitmentNeedsMd::where('id', $input['id'])->first();
 74→        if ($recruitment == null) {
 75→            return ['result' => false, 'message' => __('my_api.data_not_found')];
 76→        }
 77→        if (!in_array($recruitment->approval_status, [RecruitmentNeedsMd::APPROVAL_STATUS_WAIT_ADMIN_APPROVE, RecruitmentNeedsMd::APPROVAL_STATUS_WAIT_CHARGE_APPROVE])) {
 78→            return ['result' => false, 'message' => __('my_api.operate_not_allowed')];
 79→        }
 80→        $changeColumns = [
 81→            'needs_job_name', 'needs_category_id', 'needs_apply_type', 'education_level', 'department_id', 'active_label',
 82→            'end_date', 'work_place', 'needs_desc', 'job_requirements', 'needs_num', 'project_type', 'salary_range', 'needs_reason', 'needs_remark',
 83→        ];
 84→        $simpleLogColumns = ['needs_desc', 'job_requirements', 'needs_reason', 'needs_remark'];
 85→        $updateColumns = Arr::only($input, $changeColumns);
 86→        $changeData = [];
 87→        if (!empty($updateColumns)) {
 88→            foreach ($updateColumns as $k => $v) {
 89→                if ($recruitment->{$k} != $v) {
 90→                    if (in_array($k, $simpleLogColumns)) {
 91→                        $changeData[] = ['column' => $k, 'old_data' => '', 'new_data' => '', 'type' => 4];
 92→                    } else {
 93→                        $changeData[] = ['column' => $k, 'old_data' => $recruitment->{$k}, 'new_data' => $v, 'type' => 2];
