239→    /**
240→     * 获取OFFER状态更新所需的信息.
241→     *
242→     * @param int $rec_pro_id
243→     * @param null|string $str 状态文案（优先使用 sendHistoryKnock 计算后的文案）
244→     * @param null|string $remark 备注（用作 rejectReason 计算 Offer 状态，与前端 getOfferStatusDefault 的 rejectReason 逻辑一致）
245→     * @return array
246→     */
247→    protected function getOfferStatusUpdateInfo(int $rec_pro_id, ?string $str = null, ?string $remark = null)
248→    {
249→        $offer = \App\Models\OfferApprovalMd::where('rec_pro_id', $rec_pro_id)
250→            ->orderByDesc('id')
251→            ->first();
252→        if (!$offer) {
253→            return [];
254→        }
255→
256→        $rec = \App\Models\RecruitmentProcessionMd::find($rec_pro_id);
257→        if (!$rec) {
258→            return [];
259→        }
260→
261→        $resume = \App\Models\ResumeMd::find($rec->resume_id);
262→        if (!$resume) {
263→            return [];
264→        }
265→
266→        $job = \App\Models\JobsMd::find($offer->job_id);
267→        $department = $job ? \App\Models\JobDepartmentsMd::find($job->department_id) : null;
268→        $jobName = $job && $department ? $department->department_name.'-'.$job->job_name : '';
269→
270→        // 获取Offer创建时间
271→        $offerCreateTime = \App\Models\ResumeRecruitmentCacheMd::where('resume_id', $resume->id)
272→            ->where('type', 'create_offer')
273→            ->orderByDesc('created_at')
274→            ->value('created_at');
275→        $offerTime = $offerCreateTime ? date('Y/m/d', strtotime($offerCreateTime)) : '';
276→
277→        // 获取入职时间
278→        $waitingEntry = \App\Models\WaitingEntryMd::where('rec_pro_id', $rec_pro_id)
279→            ->orderByDesc('id')
280→            ->first();
281→        $entryTime = $waitingEntry && $waitingEntry->entry_time ? date('Y/m/d', strtotime($waitingEntry->entry_time)) : '';
282→
283→        // 获取跟进HR
284→        $followHrId = $waitingEntry ? $waitingEntry->follow_up_hr_id : $resume->inputer_user_id;
285→        $users = userInfo();
286→        $followHr = Arr::get($users, "{$followHrId}.nickname", '');
287→
288→        // 计算Offer状态：
289→        // - 优先使用 sendHistoryKnock 传下来的状态文案 $str
290→        // - 只有当 $str 是“待入职/拒入职”（一种组合文案，表示两者难以区分）或为空时，才回退用原有逻辑推导
291→        $normalizedStr = trim($str ?? '');
292→        $shouldFallbackCalculate = (
293→            $normalizedStr === ''
294→            || $normalizedStr === '取消offer/拒offer'
295→        );
296→        $hasRemark = ($remark !== null && $remark !== '');
297→        if ($shouldFallbackCalculate) {
298→            // 有 remark 时用 remark 作为 rejectReason，与前端 getOfferStatusDefault 的 rejectReason 逻辑一致
299→            $rejectReasonForStatus = $hasRemark ? $remark : ($offer->reject_reason ?? '');
300→            $offerStatus = $this->calculateOfferStatus($offer->approval_status, $rec->status, $rejectReasonForStatus, $offerTime);
301→        } else {
302→            $offerStatus = $normalizedStr;
303→        }
304→
305→        // 构建薪资信息
306→        $salaryLines = [];
307→        if ($offer->intern_salary) {
308→            $salaryLines[] = '<div style="white-space: nowrap;">实习期薪资: '.$this->markEncrString($offer->intern_salary).'</div>';
309→        }
310→        if ($offer->probation_salary) {
311→            $salaryLines[] = '<div style="white-space: nowrap;">试用期薪资: '.$this->markEncrString($offer->probation_salary).'</div>';
312→        }
313→        if ($offer->salary) {
314→            $salaryLines[] = '<div style="white-space: nowrap;">正式薪资: '.$this->markEncrString($offer->salary).'</div>';
315→        }
316→        $salaryInfo = implode('', $salaryLines);
317→        if (empty($salaryInfo)) {
318→            $salaryInfo = '-';
319→        }
320→
321→        $rejectReasonIsRemark = $hasRemark;
322→
323→        return [
324→            'username' => $resume->username,
325→            'nickname' => $resume->nickname ?? '',
326→            'job_name' => $jobName,
327→            'salary_info' => $salaryInfo,
328→            'offer_status' => $offerStatus,
329→            'offer_time' => $offerTime,
330→            'entry_time' => $entryTime,
331→            'reject_reason' => $rejectReasonIsRemark ? $remark : ($offer->reject_reason ?? ''),
332→            'reject_reason_is_remark' => $rejectReasonIsRemark,
333→            'follow_hr' => $followHr,
334→            'offer_approval_id' => $offer->id,
335→        ];
336→    }
