338→    /**
339→     * 计算Offer状态（复用前端 getOfferStatusDefault 中仅 rejectReason 相关逻辑）.
340→     *
341→     * @param string $approvalStatus
342→     * @param string $recStatus
343→     * @param string $rejectReason
344→     * @param string $offerTime
345→     * @return string
346→     */
347→    protected function calculateOfferStatus(string $approvalStatus, string $recStatus, string $rejectReason, string $offerTime): string
348→    {
349→        $statusMap = [
350→            'create_offer' => 'offer创建',
351→            'cancel_offer' => '取消offer',
352→            'reject_offer' => '拒offer',
353→            'wait_entry' => '待入职',
354→            'reject_entry' => '拒入职',
355→            'al_entry' => '已入职',
356→        ];
357→
358→        if (in_array($rejectReason, ['薪资未达预期', '有其它合适offer', '个人发展', '家庭原因', '行业原因', '工作地点原因', '工作时间原因', '工作内容原因'], true)) {
359→            return $statusMap['reject_offer'];
360→        }
361→        if (in_array($rejectReason, ['有其他合适Offer', '薪资原因', '个人发展问题'], true)) {
362→            return $statusMap['reject_entry'];
363→        }
364→        if ($rejectReason === '取消offer') {
365→            return $statusMap['cancel_offer'];
366→        }
367→        if ($rejectReason === '候选人放弃OFFER') {
368→            return $statusMap['reject_offer'];
369→        }
370→        if ($rejectReason === '候选人放弃入职') {
371→            return $statusMap['reject_entry'];
372→        }
373→        // 复用前端 getOfferStatusDefault 中仅 rejectReason 相关逻辑（stage === 'archive' 分支）
374→        if ($recStatus === 'archive') {
375→            return $statusMap['cancel_offer'];
376→        }
377→
378→        if ($recStatus === 'wait_entry') {
379→            return $statusMap['wait_entry'];
380→        }
381→
382→        if ($recStatus === 'al_entry') {
383→            return $statusMap['al_entry'];
384→        }
385→
386→        if ($approvalStatus === 'reject_offer') {
387→            return $statusMap['reject_offer'];
388→        }
389→
390→        if ($offerTime) {
391→            return $statusMap['create_offer'];
392→        }
393→
394→        return '-';
395→    }
