  1→<?php
  2→
  3→namespace App\Http\Controllers;
  4→
  5→use App\Exceptions\UserException;
  6→use App\Lib\Facade\OfficialApiLib;
  7→use App\Models\InterviewRecordsMd;
  8→use App\Models\OfferApprovalMd;
  9→use App\Models\OfferMailApprovalMd;
 10→use App\Models\RecruitmentNeedsResumeTokenMd;
 11→use App\Models\RecruitmentProcessionMd;
 12→use App\Models\ResumeMd;
 13→use App\Service\KnockService;
 14→use App\Service\SiteService;
 15→use App\Support\Common\AuthRecord;
 16→use Illuminate\Http\Request;
 17→use Illuminate\Support\Arr;
 18→
 19→class OfferMailApprovalController extends Controller
 20→{
 21→    public function search(Request $request)
 22→    {
 23→        $input = $request->all();
 24→        $users = userInfo();
 25→        $result = OfferMailApprovalMd::alias('oma')
 26→            ->join('offer_approval as oa', 'oa.id', '=', 'oma.offer_id')
 27→            ->join('recruitment_procession as rec', 'rec.id', '=', 'oa.rec_pro_id')
 28→            ->join('resumes as re', 're.id', '=', 'rec.resume_id')
 29→            ->leftjoin('jobs as b', 'b.job_id', 'oa.job_id')
 30→            ->leftjoin('job_departments as d', 'd.department_id', 'b.department_id')
 31→            ->filterIfExists([
 32→                ['oma.approval_status', 'IN', 'approval_status'],
 33→                ['oma.created_at', '>=', 'create_start_time'],
 34→                ['oma.created_at', '<=', 'create_end_time'],
 35→                ['re.username_hash', 'IN', 'username_hash_filter'],
 36→                ['re.nickname_hash', 'IN', 'nickname_hash_filter'],
 37→            ], $input)
 38→            ->selectRaw("oma.*, rec.id as rec_pro_id, re.username,re.nickname,re.id as resume_id,re.inputer_user_id, oa.job_id, CONCAT(d.department_name,'-',b.job_name) as job_name, oa.salary, oa.probation_salary, oa.intern_salary, oa.remark, oa.offer_remark")
 39→            ->orderBy('oma.id', 'desc')
 40→            ->paginate($input['per_page'] ?? 50)->toArray();
 41→
 42→        foreach ($result['data'] as &$one) {
 43→            $one['creator_name'] = Arr::get($users, "{$one['creator_id']}.nickname", '');
 44→            $one['approver_name'] = Arr::get($users, "{$one['approver_id']}.nickname", '');
 45→        }
 46→        return $this->responseJsonSuccess([
 47→            'offer_mail_approval' => $result['data'],
 48→            'current_page' => $result['current_page'],
 49→            'per_page' => $result['per_page'],
 50→            'total' => $result['total'],
 51→        ]);
 52→    }
 53→
 54→    public function deal(Request $request)
 55→    {
 56→        $input = Arr::only($request->all(), ['id', 'result', 'authorized_token']);
 57→        db()->beginTransaction();
 58→        $offerMailApproval = OfferMailApprovalMd::find($input['id']);
 59→        if (!in_array($offerMailApproval->approval_status, ['created'])) {
 60→            return $this->responseJsonFail(__('my_api.record_is_checked'), UserException::ERR_USER_OPERATE_LIMIT);
 61→        }
 62→        try {
 63→            $offerApproval = OfferApprovalMd::find($offerMailApproval->offer_id);
 64→            // 更新offer邮件审核
 65→            $offerMailApproval->update(['approval_status' => $input['result'], 'approver_id' => AuthRecord::user()->user_id, 'approval_time' => date('Y-m-d H:i:s')]);
 66→            // 更新offer信息
 67→            if ($input['result'] == 'pass') {
 68→                $newOfferRecord = empty($offerApproval->offer_send_record) ? [] : $offerApproval->offer_send_record;
 69→                $newOfferRecord[] = ['offer_pdf' => $offerApproval->offer_pdf, 'id_sign' => $offerMailApproval->id_sign, 'send_time' => date('Y-m-d H:i:s'), 'sender_id' => AuthRecord::user()->user_id];
 70→                OfficialApiLib::sendRequest(
 71→                    'official-api/common/record-id-sign',
 72→                    ['id_sign' => $offerMailApproval->id_sign, 'type' => 'offer_confirm']
 73→                );
 74→                app(\App\Service\ResumeMailService::class)->sendApplicantOfferEmail($input['id'], $input['authorized_token']);
 75→                // 已发offer
 76→                $offerApproval->update(['approval_status' => 'send_offer', 'offer_send_record' => $newOfferRecord]);
 77→            } else {
 78→                $offerApproval->update(['approval_status' => 'mail_approval_fail']);
 79→            }
 80→
 81→            // 驳回的话,删除简历和授权绑定关系
 82→            if ($input['result'] == 'fail') {
 83→                RecruitmentNeedsResumeTokenMd::where('offer_approval_id', $offerApproval->id)->delete();
 84→                $resumeId = RecruitmentProcessionMd::where('id', $offerApproval->rec_pro_id)->first()?->resume_id ?? 0;
 85→                if ($resumeId) {
 86→                    ResumeMd::where('id', $resumeId)->update(['recruitment_needs_id' => 0]);
 87→                }
 88→            }
 89→            db()->commit();
 90→        } catch (\Exception $e) {
 91→            db()->rollBack();
 92→            OfficialApiLib::sendRequest(
 93→                'official-api/common/delete-id-sign',
 94→                ['id_sign' => $offerMailApproval->id_sign, 'type' => 'offer_confirm']
 95→            );
 96→            return $this->responseJsonFail(__('my_api.update_offer_mail_check_fail').$e->getMessage(), 423);
 97→        }
 98→        return $this->responseJsonSuccess([]);
 99→    }
100→
101→    public static function sendHistoryKnock($rec_pro_id, $str, $approver_name = null, $remark = null, $authorized_token = null): void
102→    {
103→        // 非中国区，也不发通知
104→        if (SiteService::app()->isNot(SiteService::CHN)) {
105→            info('[sendHistoryKnock] 非中国区不通知 rec_pro_id='.$rec_pro_id.' 状态='.$str.($remark !== null && $remark !== '' ? ' 备注='.$remark : ''));
106→            return;
107→        }
108→
109→        // 判断是否是OFFER状态更新（offer创建、取消Offer、拒Offer、待入职、拒入职、已入职）
110→        $isOfferStatusUpdate = in_array($str, ['offer创建', '取消offer', '拒offer', '待入职', '拒入职', '已入职'])
111→            || strpos($str, 'offer创建') !== false
112→            || strpos($str, '取消offer') !== false
113→            || strpos($str, '拒offer') !== false
114→            || strpos($str, '待入职') !== false
115→            || strpos($str, '拒入职') !== false
116→            || strpos($str, '已入职') !== false;
117→
118→        // 获取OFFER信息
119→        $offer = OfferApprovalMd::where('rec_pro_id', $rec_pro_id)
120→            ->orderByDesc('id')
121→            ->first();
122→
123→        // 如果不是OFFER状态更新，则是面试状态更新，发送给所有参与面试的面试官
124→        // 获取90天内且已过去的全部面试记录（多轮面试时每位面试官都应收到通知）
125→        $allInterviews = InterviewRecordsMd::where('rec_pro_id', $rec_pro_id)
126→            ->whereRaw('DATE(interview_time) > DATE_SUB(CURDATE(), INTERVAL 90 DAY)')
127→            ->whereRaw('DATE(interview_time) <= CURDATE()')
128→            ->orderBy('round_times', 'desc')
129→            ->get();
130→
131→        $isOfferCreate = false;
132→        if ($allInterviews->isEmpty()) {
133→            info('[sendHistoryKnock] 无近期面试记录不通知面试官 rec_pro_id='.$rec_pro_id.' 状态='.$str);
134→        } else {
135→            // 判断是否是offer创建之后的状态（取消offer、拒offer、待入职、拒入职、已入职）
136→            $isOfferCreate = $str === 'offer创建' || strpos($str, 'offer创建') !== false;
137→            $isOfferStatusAfterCreate = !$isOfferCreate && (
138→                in_array($str, ['取消offer', '拒offer', '待入职', '拒入职', '已入职'])
139→                    || strpos($str, '取消offer') !== false
140→                    || strpos($str, '拒offer') !== false
141→                    || strpos($str, '待入职') !== false
142→                    || strpos($str, '拒入职') !== false
143→                    || strpos($str, '已入职') !== false
144→            );
145→
146→            // 收集所有面试官 id（去重），offer 创建后状态时排除审批人避免重复通知
147→            $interviewerIds = $allInterviews->pluck('interviewer_id')->filter()->unique()->values()->toArray();
148→            if ($isOfferStatusAfterCreate && $offer && $offer->approver_id) {
149→                $interviewerIds = array_values(array_diff($interviewerIds, [$offer->approver_id]));
150→            }
151→
152→            if (!empty($interviewerIds)) {
153→                KnockService::app()->sendInterviewHistoryMessageToSSC($interviewerIds, $rec_pro_id);
154→                info('[sendHistoryKnock] 已通知面试官招聘状态 rec_pro_id='.$rec_pro_id.' 状态='.$str.' 面试官ids='.implode(',', $interviewerIds));
155→            } elseif ($isOfferStatusAfterCreate && $offer && $offer->approver_id) {
156→                info('[sendHistoryKnock] 面试官与审批人同一人不重复发knock rec_pro_id='.$rec_pro_id.' 状态='.$str);
157→            }
158→        }
159→
160→        // 如果是OFFER状态更新，只发送给审批人
161→        if ($isOfferStatusUpdate) {
162→            if ($offer && $offer->approver_id) {
163→                $approverId = $offer->approver_id;
164→
165→                // offer创建时，发送审批邮件（offer_check模板）
166→                if ($isOfferCreate) {
167→                    // 发送offer审批邮件
168→                    if ($approver_name && $authorized_token) {
169→                        try {
170→                            app(\App\Service\ResumeMailService::class)->sendOfferCheckEmail(
171→                                [$offer->id],
172→                                $approver_name,
173→                                $remark ?? '',
174→                                $authorized_token
175→                            );
176→                            info('[sendHistoryKnock] 已发offer审批邮件 rec_pro_id='.$rec_pro_id.' 审批人='.$approverId);
177→                        } catch (\Exception $e) {
178→                            info('[sendHistoryKnock] offer审批邮件发送失败 rec_pro_id='.$rec_pro_id.' 审批人='.$approverId.' 错误='.$e->getMessage());
179→                        }
180→                    }
181→                } else {
182→                    // 其他状态（取消offer、拒offer、待入职、拒入职、已入职）发送状态更新邮件
183→                    try {
184→                        app(\App\Service\ResumeMailService::class)->sendOfferStatusUpdateEmail($rec_pro_id, $approverId, $str, $remark);
185→                        info('[sendHistoryKnock] 已发offer状态更新邮件 rec_pro_id='.$rec_pro_id.' 状态='.$str.' 审批人='.$approverId);
186→                    } catch (\Exception $e) {
187→                        info('[sendHistoryKnock] offer状态更新邮件发送失败 rec_pro_id='.$rec_pro_id.' 审批人='.$approverId.' 错误='.$e->getMessage());
188→                    }
189→                }
190→
191→                // 发送Knock通知
192→                $robotName = config('my_knock.hrmgt_notification_robot_name');
193→                $content = config('my_notification_template.hr-offer-approval-update');
194→                if ($isOfferCreate) {
195→                    $content = config('my_notification_template.hr-offer-approval-update-start');
196→                }
197→                // 附带offer审批id和状态参数，便于前端跳转到已审批状态并定位到具体数据
198→                $content = $content.'&id='.$offer->id;
199→                KnockService::app()->sendPlaintextRobotMessage($content, $robotName, [$approverId]);
200→                info('[sendHistoryKnock] 已发审批人Knock通知 rec_pro_id='.$rec_pro_id.' 状态='.$str.' 审批人='.$approverId);
201→            }
202→        }
203→    }
204→}
