file.content:
        waitTable: [],
        doneTable: [],

        offerPath: '',

        // 用于URL参数定位
        offerId: null,
        isFirstLoad: true,
    }
},

created() {
    // 从URL参数读取status，用于定位到已审批状态
    const status = this.$route.query.status
    if (status === 'bo_done') {
        this.benchOfferType = 'bo_done'
    }
    // 从URL参数读取id，用于定位到具体数据
    const id = this.$route.query.id
    if (id) {
        this.offerId = id
    }
},

computed: {
    apiList() {
        const mainApi = this.appUri
        // const offerApi = 'offer-mail-approval'
        const commonApi = 'common'
        const usrApi = 'interview-workbench'

        return {
            offerSearchApi: mainApi,
            commonSettingApi: commonApi + '/get-config',
            detailUrl: usrApi + '/candidate-details',
        }
    },

    filteredTableData() {
        let allTableData = this.benchOfferType === 'bo_wait' ? this.waitTable : this.doneTable
        // 首次加载且有id参数时，筛选出对应的数据
        if (this.isFirstLoad && this.offerId) {
            allTableData = allTableData.filter(item => {
                // target_id 是 offer_approval 的 id
                return item.target_id === Number(this.offerId)
            })
        }
        return this.filterTableData(allTableData)
    },

    tableData() {
        return this.filteredTableData.slice((this.page - 1) * this.pageSize, this.page * this.pageSize)
    },

    totalNum() {
        return this.filteredTableData.length
    },
    searchBarOptions() {
        if (this.benchOfferType === 'bo_wait') {
            return [
                { label: this.$t('t0001'), value: 'username', display: 'input', repeatable: true },
            ]
        }
        return [
            { label: this.$t('t0001'), value: 'username', display: 'input', repeatable: true },
            {
                label: this.$t('t0344'),
                value: 'offer_status',
                display: 'select',
                data_source: this.offerStatusOptions,
                isOutside: true,
            },
        ]
    },
    tabOptList() {
        return [
            { label: this.$t('t0104'), value: 'bo_wait' },
            { label: this.$t('t0105'), value: 'bo_done' },
        ]
    },

    offerStatusOptions() {
        const values = ['create_offer', 'cancel_offer', 'reject_offer', 'wait_entry', 'reject_entry', 'al_entry']
        return INTERVIEW_STATUS.filter(item => values.includes(item.value))
    },
},

watch: {
    benchOfferType() {
        this.page = 1
    },
},

mounted() {
    // 更新 config 防止其他用户更新未同步
    this.$store.dispatch(aTypes.GET_COMMON_CONFIG)
    this.doSearch()
},

methods: {
    doSearch() {
        this.$store.dispatch(aTypes.AJAX_SDK, {
            webApi: this.apiList.offerSearchApi,
            success: res => {
                const resData = (res.offers || [])
                    .map(item => {
                        const offerStatus = getOfferStatusDefault(
                            item.approval_status,
                            item.rec_pro_status,
                            item.reject_reason || '',
                            item.offer_create_time || '',
                        )
                        return {
                            ...item,
                            offer_status: offerStatus,
                        }
                    })
                    .sort((a, b) => (moment(a.created_at) > moment(b.created_at) ? -1 : 1))
                // hsq 测试代码
                // if (this.$route.query.copy) {
                //     Array(+this.$route.query.copy).fill().forEach(() => {
                //         resData = [...resData, ...resData]
                //     })
                // }

                this.waitTable = resData.filter(el => el.approval_status === 'waiting' && (!el.rec_pro_status || el.rec_pro_status !== 'archive'))
                this.doneTable = resData.filter(el => el.approval_status !== 'waiting')
            },
            failure: () => {
                this.waitTable = []
                this.doneTable = []
            },
        })
    },

    // 切换上一个
    onClickPrev() {
        if (this.currentDetailIndex > 0) {
            this.currentDetailIndex -= 1
        }
    },

    // 切换下一个
    onClickNext() {
        if (this.currentDetailIndex < this.tableData.length - 1 && this.currentDetailIndex > -1) {
            this.currentDetailIndex += 1
        }
    },

    showCandidateDetail(rowData, showDrawer = true) {
        // 更新索引
        this.rowData = rowData
        this.currentDetailIndex = this.tableData.findIndex(el => el.id === rowData.id)

        this.showResumeDrawer = showDrawer
